const res = $input.first().json;
const rows = res.values || [];
let pendingRows = [];
for (let i = 0; i < rows.length; i++) {
  const s = (rows[i][11] || '').toString().toUpperCase().trim();
  if (s === 'PENDING') { pendingRows.push({ idx: i, row: rows[i] }); }
}
if (pendingRows.length === 0) throw new Error('No PENDING topic in Content Master Table. Set STATUS (col L) = PENDING for a row.');
const found = pendingRows[Math.floor(Math.random() * pendingRows.length)];
const sheetRow = found.idx + 4;
return [{
  json: {
    job_id:             (found.row[0] || '').trim() || ('PHY-' + Date.now().toString().slice(-8)),
    topic:              (found.row[1] || '').trim(),
    category:           (found.row[2] || '').trim(),
    core_theory:        (found.row[3] || '').trim(),
    scientific_depth:   (found.row[4] || '').trim(),
    hook_line:          (found.row[5] || '').trim(),
    narrative_angle:    (found.row[6] || '').trim(),
    visual_suggestions: (found.row[7] || '').trim(),
    target_audience:    (found.row[8] || '').trim(),
    post_format:        (found.row[9] || '').trim(),
    difficulty:         (found.row[10] || 'advanced').trim(),
    duration_min:       0.33,
    sheet_row:          sheetRow,
    source:             'google_sheet'
  }
}];

const raw       = $input.first().json;
const body      = (raw.body !== undefined) ? raw.body : raw;

let sheetData = {};
try { sheetData = $('Pick PENDING Topic').first().json; } catch(e) {}

const jobId      = body.job_id      || raw.job_id      || sheetData.job_id      || ('PHY-' + Date.now().toString().slice(-8));
const topic      = body.topic       || raw.topic       || sheetData.topic;
const sheetRow   = body.sheet_row   || raw.sheet_row   || sheetData.sheet_row   || null;
const difficulty = body.difficulty  || raw.difficulty  || sheetData.difficulty  || 'advanced';
const durationMin = parseFloat(body.duration_min || raw.duration_min || sheetData.duration_min) || 0.33;

if (!topic) throw new Error('No topic found. Check Google Sheet.');

const durationSec = Math.round(durationMin * 60);
const numClips    = Math.max(2, Math.ceil(durationSec / 5));
const wordTarget  = Math.min(52, Math.max(15, Math.round(durationSec * 2.5)));

return [{ json: {
  ...sheetData,
  job_id: jobId, topic, difficulty, sheet_row: sheetRow,
  duration_min: durationMin, duration_sec: durationSec,
  num_clips: numClips, word_target: wordTarget,
  start_time: Date.now()
}}];

const response  = $input.first().json;
const jobConfig = $('Set Job Config').first().json;
const expectedClips = jobConfig.num_clips || 6;

if (!response.candidates || !response.candidates[0] || !response.candidates[0].content)
  throw new Error('Gemini response empty');

let rawText = response.candidates[0].content.parts[0].text.trim();
rawText = rawText.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();

let parsed;
try { parsed = JSON.parse(rawText); }
catch(e) {
  const s = rawText.indexOf('{'), endIndex = rawText.lastIndexOf('}');
  parsed = JSON.parse((s !== -1 && endIndex !== -1) ? rawText.slice(s, endIndex+1) : rawText);
}

if (!parsed.scenes || !Array.isArray(parsed.scenes))
  throw new Error('Gemini returned no scenes array');

// Strict scene count validation
if (parsed.scenes.length !== expectedClips) {
  console.warn('Gemini returned ' + parsed.scenes.length + ' scenes, expected ' + expectedClips + '. Fixing...');
  if (parsed.scenes.length < expectedClips) {
    // Pad missing scenes by duplicating the last scene with adjusted timing
    while (parsed.scenes.length < expectedClips) {
      const i = parsed.scenes.length;
      const last = parsed.scenes[parsed.scenes.length - 1];
      parsed.scenes.push({
        ...last,
        scene_number: i + 1,
        start_sec: i * 5,
        end_sec: (i + 1) * 5,
        narration_segment: last.narration_segment
      });
    }
  } else {
    // Trim extra scenes
    parsed.scenes = parsed.scenes.slice(0, expectedClips);
  }
}

console.log('Scenes validated: ' + parsed.scenes.length + ' scenes for ' + jobConfig.duration_sec + 's video');

const clip_prompts    = parsed.scenes.map(s => s.visual_prompt);
const negative_prompts = parsed.scenes.map(s => s.negative_prompt || 'text, letters, numbers, labels, watermarks, UI, human faces, cartoon, anime, blurry, low quality');

return [{ json: {
  ...jobConfig,
  narration:       parsed.narration,
  scenes:          parsed.scenes,
  clip_prompts,
  negative_prompts,
  title:           parsed.title    || jobConfig.topic,
  hashtags:        parsed.hashtags || '#physics #science',
  highlight_keywords: parsed.highlight_keywords || []
}}];

const fs           = require('fs');
const { execSync } = require('child_process');

const data  = $input.first().json;
const jobId = data.job_id;
const clips = (data.clip_prompts || []);

const clipCount = clips.length;
const CLIP_DUR  = 5.0;
const FADE_DUR  = 0.3;
const videoDuration = clipCount > 0
  ? (clipCount * CLIP_DUR - Math.max(0, clipCount - 1) * FADE_DUR)
  : 20;

// ── Analyse visual prompts ────────────────────────────────────────
const visual = clips.join(' ').toLowerCase();

const hasGravity   = /gravitational|spacetime|curvature|warp|black hole|event horizon|singularity/.test(visual);
const hasQuantum   = /wave function|probability|interference|quantum|superposit|orbital|electron cloud/.test(visual);
const hasParticle  = /particle|collision|detector|bubble chamber|track|beam/.test(visual);
const hasElectric  = /electric|plasma|lightning|arc|field line|magnetic|discharge/.test(visual);
const hasStellar   = /star|sun|solar|pulsar|supernova|neutron|fusion|corona/.test(visual);
const hasAtomic    = /atom|molecule|crystal|lattice|bond|nucleus|proton|neutron/.test(visual);
const hasWave      = /wave|ripple|oscillat|vibrat|resonan|frequency|diffract/.test(visual);
const hasLaser     = /laser|photon|beam|ray|light pulse|optic/.test(visual);
const isIntense    = /explo|burst|rapid|flash|collision|spark|surge|collaps|impact/.test(visual);
const isCalm       = /slow|drift|float|fade|gentle|subtle|still|hover/.test(visual);

// ── Pick best matching track from /ffmpeg/config/bgm/ ────────────
// Tracks available:
//  Arcane       — dark mysterious ambient          → quantum, wave, laser
//  BlackVortex  — dark cinematic swirl             → gravity, black hole
//  Anxiety      — tense building suspense          → intense, particle collision
//  Anguish      — heavy dark atmospheric           → stellar explosion, supernova
//  Apprehension — quiet suspense build             → calm quantum, atomic
//  Anachronist  — sci-fi electronic                → electric, plasma, magnetic
//  Artifact     — tech/lab sci-fi atmospheric      → lab, atomic, crystal
//  BlipStream   — electronic particle blips        → particle detector, beam
//  Blipotron    — electronic sci-fi drone          → electric, wave, frequency
//  Anamalie     — eerie mysterious anomaly feel    → quantum entanglement, anomaly

let trackName;

if (hasGravity && isIntense)           trackName = 'IndustrialCinematic'; // heavy industrial = black hole/intense gravity
else if (hasGravity)                   trackName = 'BlackVortex';         // dark vortex = gravity/black hole
else if (hasStellar && isIntense)      trackName = 'Anguish';             // heavy dark = stellar explosion
else if (hasStellar)                   trackName = 'LightlessDawn';       // cinematic space = stellar ambient
else if (hasParticle && isIntense)     trackName = 'ImpactIntermezzo';    // dramatic impact = particle collision
else if (hasParticle)                  trackName = 'BlipStream';          // blips = particle detector
else if (hasElectric && isIntense)     trackName = 'Electrodoodle';       // electric sci-fi = intense plasma
else if (hasElectric)                  trackName = 'Anachronist';         // sci-fi electronic = plasma/magnetic
else if (hasWave && hasLaser)          trackName = 'Blipotron';           // electronic = wave/laser
else if (hasQuantum && isCalm)         trackName = 'Apprehension';        // quiet suspense = calm quantum
else if (hasQuantum && isIntense)      trackName = 'DarkFog';             // dark tension = intense quantum
else if (hasQuantum)                   trackName = 'Arcane';              // mysterious = quantum
else if (hasAtomic)                    trackName = 'Artifact';            // tech lab = atomic/crystal
else if (hasWave)                      trackName = 'Anamalie';            // eerie = wave anomaly
else if (isIntense)                    trackName = 'Anxiety';             // tense = intense scenes
else if (isCalm)                       trackName = 'Odyssey';             // epic calm = general physics
else                                   trackName = 'Arcane';              // default: dark mysterious ambient

const bgmLibPath  = '/ffmpeg/config/bgm/' + trackName + '.mp3';
const bgmN8nPath  = '/data/ffmpeg/input/' + jobId + '_bgm.mp3';
const bgmContPath = '/ffmpeg/input/'      + jobId + '_bgm.mp3';

// Verify track exists in container
const checkCmd = 'docker exec ffmpeg-runner test -f "' + bgmLibPath + '" && echo EXISTS || echo MISSING';
const checkResult = execSync(checkCmd, { encoding: 'utf-8', timeout: 10000 });

if (!checkResult.includes('EXISTS')) {
  throw new Error('BGM track not found in container: ' + bgmLibPath + '. Make sure /ffmpeg/config/bgm/ folder is mounted.');
}

// Trim + fade the selected track to exactly videoDuration seconds
const trimCmd =
  'docker exec ffmpeg-runner ffmpeg -y ' +
  '-i "' + bgmLibPath + '" ' +
  '-t ' + videoDuration.toFixed(3) + ' ' +
  '-af "afade=t=in:st=0:d=1.5,afade=t=out:st=' + (videoDuration - 1.5).toFixed(3) + ':d=1.5,volume=0.3" ' +
  '-acodec libmp3lame -ab 128k ' +
  '"' + bgmContPath + '" 2>&1 && echo TRIM_OK';

console.log('BGM track selected: ' + trackName + ' | duration: ' + videoDuration.toFixed(1) + 's');
const trimResult = execSync(trimCmd, { encoding: 'utf-8', timeout: 30000 });
if (!trimResult.includes('TRIM_OK')) throw new Error('BGM trim failed: ' + trimResult.slice(-300));

console.log('BGM ready: ' + bgmN8nPath);

return [{ json: {
  ...data,
  audio_path:      null,
  subs_path:       null,
  audio_duration:  videoDuration,
  subtitle_chunks: [],
  word_timings:    [],
  word_count:      0,
  bgm_path:        bgmN8nPath
}}];

const researchResp = $input.first().json;
const jobData = $('Set Job Config').first().json;
let researchText = '';
try {
  researchText = researchResp.candidates[0].content.parts[0].text || '';
} catch(e) {
  researchText = 'No research available.';
}
console.log('Research obtained: ' + researchText.slice(0, 100) + '...');
return [{ json: { ...jobData, topic_research: researchText } }];
